def build_prompt(user_msg: str, retrieved_docs: list[str]) -> str:
    if detect_pattern(user_msg).blocked:
        raise ValueError("Injection detected")
    # BUG: retrieved_docs go in unscanned -- easy indirect injection
    context = "\n".join(retrieved_docs)
    return f"Context:\n{context}\n\nQuestion: {user_msg}"


# RIGHT: scan every input source independently
def build_prompt_safe(user_msg: str, retrieved_docs: list[str]) -> str:
    if detect_pattern(user_msg).blocked:
        raise ValueError("Injection detected in user message")
    safe_docs = []
    for i, doc in enumerate(retrieved_docs):
        if detect_pattern(doc).blocked:
            # Replace suspicious doc with a notice rather than crashing
            safe_docs.append(f"[Document {i+1}: content withheld -- security policy]")
        else:
            safe_docs.append(doc)
    context = "\n".join(safe_docs)
    return f"Context:\n{context}\n\nQuestion: {user_msg}"

# WRONG: reveals detection internals to the caller
result = detect_pattern(user_input)
if result.blocked:
    return {"error": f"Pattern matched: '{result.matched_pattern}', score={result.risk_score}"}

# RIGHT: generic error message with a correlation ID for internal lookup
import uuid
if result.blocked:
    incident_id = str(uuid.uuid4())[:8]
    logger.warning("Injection blocked", extra={
        "incident_id": incident_id,
        "pattern": result.matched_pattern,
        "score": result.risk_score,
    })
    return {"error": "input_policy_violation", "incident_id": incident_id,
            "message": "Your request could not be processed. Contact support if this is unexpected."}
